#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;

struct Node{
    double s,v;
    Node operator+(Node res)const{
        return {s+res.s,v+res.v};
    }
}t[N<<2];

int n,m;
double a[N],tag[N<<2];

void put_tag(int cur,int l,int r,double k){
    t[cur].v+=2*k*t[cur].s+(r-l+1)*k*k;
    t[cur].s+=(r-l+1)*k;
    tag[cur]+=k;
}

void build(int cur,int l,int r){
    if(l==r){
        t[cur].s=a[l],t[cur].v=a[l]*a[l];
        return;
    }
    int mid=l+r>>1;
    build(cur*2,l,mid);
    build(cur*2+1,mid+1,r);
    t[cur]=t[cur*2]+t[cur*2+1];
}

void modify(int cur,int l,int r,int x,int y,double k){
    if(x<=l && r<=y){
        put_tag(cur,l,r,k);
        return;
    }
    int mid=l+r>>1;
    if(tag[cur]!=0){
        put_tag(cur*2,l,mid,tag[cur]);
        put_tag(cur*2+1,mid+1,r,tag[cur]);
        tag[cur]=0;
    }
    if(x<=mid)
        modify(cur*2,l,mid,x,y,k);
    if(y>mid)
        modify(cur*2+1,mid+1,r,x,y,k);
    t[cur]=t[cur*2]+t[cur*2+1];
}

Node query(int cur,int l,int r,int x,int y){
    if(x<=l && r<=y)
        return t[cur];
    int mid=l+r>>1;
    if(tag[cur]!=0){
        put_tag(cur*2,l,mid,tag[cur]);
        put_tag(cur*2+1,mid+1,r,tag[cur]);
        tag[cur]=0;
    }
    Node ans={0,0};
    if(x<=mid)
        ans=ans+query(cur*2,l,mid,x,y);
    if(y>mid)
        ans=ans+query(cur*2+1,mid+1,r,x,y);
    return ans;
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%lf",&a[i]);
    build(1,1,n);
    while(m--){
        int op,l,r;
        double k;
        scanf("%d%d%d",&op,&l,&r);
        if(op==1){
            scanf("%lf",&k);
            modify(1,1,n,l,r,k);
        }else if(op==2)
            printf("%.4lf\n",query(1,1,n,l,r).s/(r-l+1));
        else{
            Node tmp=query(1,1,n,l,r);
            printf("%.4lf\n",tmp.v/(r-l+1)-(tmp.s/(r-l+1))*(tmp.s/(r-l+1)));
        }
    }
    return 0;
}
